static const int sUnicodeTableSize = 694;

#include <Core/Core.h>

struct WidthCache {
	dword chr = 0xFFFFFFFF;
	byte w1 = 1;
	byte w2 = 1;
};

static thread_local WidthCache sWidthCache[256];

int VTCell::GetWidth(int ambiguouswidth) const
{
	if(style.image || chr < 768)
		return 1;

	int i = (chr ^ (chr >> 8)) & 255;
	
	if(__builtin_expect(sWidthCache[i].chr == chr, 1))
		return (ambiguouswidth == 2) ? sWidthCache[i].w2 : sWidthCache[i].w1;
	
	int l = 0, r = sUnicodeTableSize - 1;
	while(l <= r) {
		int mid = (l + r) >> 1;
		const auto& range = sUnicodeWidthTable[mid];
		if(chr < range.a) {
			r = mid - 1;
		} else
		if(chr > range.b) {
			l = mid + 1;
		}
		else {
			sWidthCache[i] = {chr, range.w1, range.w2};
			return (ambiguouswidth == 2) ? range.w2 : range.w1;
		}
	}
	sWidthCache[i] = {chr, 1, 1};
	return 1;
}

void VTCell::Fill(const VTCell& filler, dword flags)
{
	if(flags == FILL_NORMAL) {
		*this = filler;
		return;
	}
	
	if(((flags & FILL_DEC_SELECTIVE) && attr.protect_dec)
	|| ((flags & FILL_ISO_SELECTIVE) && attr.protect_iso)) {
		return;
	}
	
	if(flags & FILL_CHAR)
		chr = filler.chr;
	
	if(flags & FILL_ATTRS)
		attrs = filler.attrs;
		
	if(flags & FILL_DATA)
		data = filler.data;
		
	if(flags & FILL_INK)
		ink = filler.ink;
		
	if(flags & FILL_PAPER)
		paper = filler.paper;
		
	if(flags & FILL_SGR)
		sgr = filler.sgr;
	else
	if(flags & XOR_SGR)
		sgr ^= filler.sgr;
}

void VTCell::Reset()
{
	ink   = Null;
	paper = Null;
	sgr   = 0;
	data  = 0;
}

bool VTCell::IsNullInstance() const
{
	return IsVoid()
		|| (chr  == 0
		&& data  == 0
		&& attrs == 0
		&& sgr   == 0
		&& IsNull(ink)
		&& IsNull(paper));
}

const VTCell& VTCell::Void()
{
	static VTCell sCell;
	return sCell;
}

hash_t VTCell::GetHashValue() const
{
	hash_t a = CombineHash(chr, data, attrs, sgr);
	hash_t b = CombineHash(ink, paper);
	return CombineHash(a, b);
}

void VTCell::Serialize(Stream& s)
{
	int version = 1;
	s / version;
	if(version >= 1) {
		s % chr;
		s % data;
		s % attrs;
		s % sgr;
		s % ink;
		s % paper;
	}
}
